class IPRateLimiter(BaseHTTPMiddleware):
    async def dispatch(self, request, call_next):
        path = request.url.path
        if not any(path.startswith(p) for p in self.protected):
            return await call_next(request)
        ip = request.client.host if request.client else "anon"
        now = time.monotonic()
        with self._lock:
            dq = self._hits.setdefault(ip, deque())
            while dq and (now - dq[0]) > self.window: dq.popleft()
            if len(dq) >= self.rate:
                return JSONResponse({"detail": "rate limit exceeded"}, status_code=429,
                                    headers={"Retry-After": str(self.window)})
            dq.append(now)
        return await call_next(request)

def hamming_distance(a: int, b: int) -> int:
    return bin(a ^ b).count("1")

def find_close_matches(target: int, known, max_distance: int = 5):
    return [m for m in known if hamming_distance(target, m.hash) <= max_distance]

def _max_run(values, predicate) -> int:
    best = run = 0
    for v in values:
        if predicate(v): run += 1; best = max(best, run)
        else: run = 0
    return best

