_ph = PasswordHasher(time_cost=3, memory_cost=64*1024, parallelism=4, hash_len=32, salt_len=16)

def verify_password(plain, encoded) -> bool:
    if encoded.startswith("$argon2"): return _ph.verify(encoded, plain)
    if encoded.startswith("pbkdf2-sha256$"): return _verify_pbkdf2(plain, encoded)
    return False

def needs_rehash(encoded) -> bool:
    return not encoded.startswith("$argon2") or _ph.check_needs_rehash(encoded)
